import { invertColorPalette } from './invert-color-palette.js';
import type {
  ColorPalette,
  ColorPaletteDefinition,
} from '../types/color-palette.js';

/**
 * Maps all the basic color palettes, creating an inverted one for each of them.
 * @param coloringMap - All the basic color palettes without the inverted.
 * @returns - The whole color palette object
 */
export const prepareInvertedColorPalette = (
  coloringMap: Record<
    ColorPalette,
    ColorPaletteDefinition | Record<string, string>
  >,
) => {
  return Object.keys(coloringMap).reduce((acc, key) => {
    acc[key] = coloringMap[key as ColorPalette];
    acc[`${key}-inverted`] = invertColorPalette(acc[key]);

    return acc;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
  }, {} as any);
};
